import React, { useState } from 'react';
import { ChevronLeft, ArrowUpCircle, Wallet } from 'lucide-react';

export default function AddGoalFundScreen({ goal, onBack, onConfirm }) {
  const [amount, setAmount] = useState('');
  const activeGoal = goal || { title: 'Dream House', current: 12500 };
  const quickAmounts = [10, 50, 100, 500];

  const handleNumberClick = (num) => {
    if (amount.length < 10) setAmount(prev => prev + num);
  };

  const handleDelete = () => setAmount(prev => prev.slice(0, -1));

  return (
    <div className="flex flex-col bg-white animate-in slide-in-from-right duration-300">
      {/* Header */}
      <div className="flex items-center gap-3 px-6 py-4 sticky top-0 bg-white z-10">
        <button onClick={onBack} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
          <ChevronLeft className="w-6 h-6 text-gray-800" />
        </button>
        <h1 className="text-xl font-black text-gray-900">Add Funds</h1>
      </div>

      <div className="flex-1 px-6 overflow-y-auto scrollbar-hide">
        {/* Goal Card */}
        <div className="mt-4 p-5 bg-emerald-50 rounded-[2rem] border border-emerald-100 flex items-center justify-between mb-10">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-[#00875A] shadow-sm">
              <ArrowUpCircle size={24} />
            </div>
            <div>
              <p className="text-[10px] text-emerald-600 font-black uppercase tracking-widest">Contributing to</p>
              <p className="font-black text-gray-900">{activeGoal.title}</p>
            </div>
          </div>
          <div className="text-right">
            <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Balance</p>
            <p className="font-black text-gray-900">${activeGoal.current.toLocaleString()}</p>
          </div>
        </div>

        {/* Amount Display */}
        <div className="text-center mb-10">
          <p className="text-[10px] text-gray-400 font-black uppercase tracking-[0.2em] mb-2">Enter Amount</p>
          <div className="flex items-center justify-center gap-1">
            <span className="text-4xl font-black text-gray-900">$</span>
            <span className={`text-6xl font-black tracking-tighter ${amount ? 'text-gray-900' : 'text-gray-200'}`}>
              {amount || '0'}
            </span>
          </div>
        </div>

        {/* Quick Add Buttons */}
        <div className="flex justify-between gap-3 mb-10">
          {quickAmounts.map((amt) => (
            <button
              key={amt}
              onClick={() => setAmount(amt.toString())}
              className="flex-1 py-3 rounded-2xl bg-gray-50 border border-gray-100 font-black text-gray-600 hover:bg-emerald-50 hover:border-emerald-200 hover:text-[#00875A] transition-all active:scale-95"
            >
              +${amt}
            </button>
          ))}
        </div>

        {/* Keypad */}
        <div className="grid grid-cols-3 gap-4 mb-8">
          {[1,2,3,4,5,6,7,8,9,'.',0].map((num) => (
            <button key={num} onClick={() => handleNumberClick(num.toString())} className="h-16 flex items-center justify-center text-2xl font-black text-gray-800 hover:bg-gray-50 rounded-2xl active:scale-90 transition-all">{num}</button>
          ))}
          <button onClick={handleDelete} className="h-16 flex items-center justify-center text-2xl font-black text-gray-800 hover:bg-gray-50 rounded-2xl active:scale-90 transition-all">
            <ChevronLeft size={24} />
          </button>
        </div>
      </div>

      {/* Footer */}
      <div className="pb-16 bg-white border-t border-gray-50">
        <div className="flex items-center justify-center gap-2 mb-4 text-gray-400">
          <Wallet size={14} />
          <p className="text-[10px] font-black uppercase tracking-widest">Source: Main Wallet ($1,500.00)</p>
        </div>
        <button 
          disabled={!amount || parseFloat(amount) <= 0}
          onClick={() => onConfirm(Number(amount))}
          className="w-[90%] py-5 rounded-[2rem] font-black text-white bg-[#00875A] shadow-xl
           shadow-emerald-100 active:scale-[0.98] transition-all disabled:opacity-50 disabled:shadow-none items-center justify-center"
        >
          Confirm Deposit
        </button>
      </div>
    </div>
  );
}
